54: // This is a container class for either an oop or a continuation address for
55: // mark stack entries. Both are pushed onto the mark stack.
56: class G1TaskQueueEntry {
57: private:
58:   void* _holder;
59: 
60:   static const uintptr_t ArraySliceBit = 1;
61: 
62:   G1TaskQueueEntry(oop obj) : _holder(obj) {
63:     assert(_holder != nullptr, "Not allowed to set null task queue element");
64:   }
65:   G1TaskQueueEntry(HeapWord* addr) : _holder((void*)((uintptr_t)addr | ArraySliceBit)) { }
66: public:
67: 
68:   G1TaskQueueEntry() : _holder(nullptr) { }
69:   // Trivially copyable, for use in GenericTaskQueue.
70: 
71:   static G1TaskQueueEntry from_slice(HeapWord* what) { return G1TaskQueueEntry(what); }
72:   static G1TaskQueueEntry from_oop(oop obj) { return G1TaskQueueEntry(obj); }
73: 
74:   oop obj() const {
75:     assert(!is_array_slice(), "Trying to read array slice " PTR_FORMAT " as oop", p2i(_holder));
76:     return cast_to_oop(_holder);
77:   }
78: 
79:   HeapWord* slice() const {
80:     assert(is_array_slice(), "Trying to read oop " PTR_FORMAT " as array slice", p2i(_holder));
81:     return (HeapWord*)((uintptr_t)_holder & ~ArraySliceBit);
82:   }
83: 
84:   bool is_oop() const { return !is_array_slice(); }
85:   bool is_array_slice() const { return ((uintptr_t)_holder & ArraySliceBit) != 0; }
86:   bool is_null() const { return _holder == nullptr; }
87: };
